private BiometricPrompt.AuthenticationCallback callback = new BiometricPrompt.AuthenticationCallback() {  
    @Override    
    public void onAuthenticationSucceeded(BiometricPrompt prompt, int result) {               //when fingerprint unlock succeeded               
        SharedPreferences sharedPref = getSharedPreferences("myApp", MODE_PRIVATE);      //accessing the preference        
        SharedPreferences.Editor editor=sharedPref.edit();                                                  //create and edit data in preferences      
         
        Editor editor = sharedPref.edit() ; 
    	editor .putString( "fingerprintAuthStatus", String.valueOf("Success"));                      //Store auth status             
         editor.commit ();                                                                           
           prompt.cancel();  
    }     
 };                      
                 
 @Override      
 public void onAuthenticationFailed() { 
     SharedPreferences sharedPref = getSharedPreferences ("myApp", MODE_PRIVATE) ;               //accessing the preference            
         Editor editor=sharedPref.edit();                                                                          
         	editor .putString( "fingerprintAuthStatus","failed" );                                               
             		 	 									   	   			      						  	     
 }               
                 
